import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Check if input exceeds buffer size
        if (input.length() > 10) {
            System.out.println("Input exceeds maximum length of 10 characters.");
            return;
        }

        // Copy input into buffer safely
        char[] buffer = new char[10];
        System.arraycopy(input.toCharArray(), 0, buffer, 0, Math.min(input.length(), 10));

        System.out.println("Hello, " + String.valueOf(buffer));
    }
}

